def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize grouped data structure
    grouped_data = defaultdict(
        lambda: {
            'count': 0,
            'sum_score': 0.0,
            'max_score': -float('inf'),
            'min_score': float('inf'),
            'custom_aggregates': defaultdict(list)
        }
    )

    # Handle missing aggregation functions by setting defaults
    if aggregation_funcs is None:
        aggregation_funcs = {
            'count': len,
            'avg_score': lambda x: sum(x) / len(x) if x else 0.0,
            'max_score': max,
            'min_score': min
        }

    # Process each search result
    for result in search_results:
        # Extract metadata value for the group_by_field
        group_value = result.metadata.get(group_by_field)

        # Handle missing grouping field values
        if group_value is None:
            group_value = 'unknown'

        # Access group statistics dictionary
        group_stats = grouped_data[group_value]

        # Update default statistics
        group_stats['count'] += 1
        group_stats['sum_score'] += result.score
        if result.score > group_stats['max_score']:
            group_stats['max_score'] = result.score
        if result.score < group_stats['min_score']:
            group_stats['min_score'] = result.score

        # Update custom aggregation fields
        for field_name, func in aggregation_funcs.items():
            # Skip default statistics fields to avoid duplication
            if field_name in ['count', 'avg_score', 'max_score', 'min_score']:
                continue

            # Extract field value (check top-level fields first, then metadata)
            field_value = None
            if field_name == 'id':
                field_value = result.id
            elif field_name == 'score':
                field_value = result.score
            elif field_name == 'text':
                field_value = result.text
            else:
                field_value = result.metadata.get(field_name)

            # Append value to custom aggregation list
            group_stats['custom_aggregates'][field_name].append(field_value)

    # Build final aggregated results dictionary
    aggregated_results = {}
    for group_value, stats in grouped_data.items():
        # Skip groups with no results
        if stats['count'] == 0:
            continue

        # Calculate average score
        avg_score = stats['sum_score'] / stats['count']

        # Prepare default statistics
        default_stats = {
            'count': stats['count'],
            'avg_score': avg_score,
            'max_score': stats['max_score'],
            'min_score': stats['min_score']
        }

        # Apply custom aggregation functions
        custom_stats = {}
        for field_name, value_list in stats['custom_aggregates'].items():
            if value_list:  # Only apply function if there are values
                try:
                    custom_stats[field_name] = aggregation_funcs[field_name](value_list)
                except Exception as e:
                    # Handle potential errors in custom functions
                    custom_stats[field_name] = f"Error: {str(e)}"

        # Combine default and custom statistics
        group_result = {**default_stats, **custom_stats}
        aggregated_results[group_value] = group_result

    return aggregated_results

